func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Inject the order map as a global variable named "order"
	if err := vm.Set("order", order); err != nil {
		return 0, fmt.Errorf("failed to set order variable: %w", err)
