	}

	script := `
		var discount = 0;

		// Base discount for orders over 100
		if (order.total > 100) {
			discount += order.total * 0.1;
		}

		// Additional discount for members
		if (order.isMember) {
			if (order.memberLevel === "gold") {
				discount += order.total * 0.15;
			} else if (order.memberLevel === "silver") {
